5527   if (!match(Phi->getOperand(0u),
5528              m_OneUse(m_Shuffle(m_Value(Op), m_Poison(), m_Mask(Mask0)))) ||
5529       !match(Phi->getOperand(1u),
5530              m_OneUse(m_Shuffle(m_Specific(Op), m_Poison(), m_Mask(Mask1)))))
5531     return false;
5532 
5533   auto *Shuf = cast<ShuffleVectorInst>(Phi->getOperand(0u));
5534 
5535   // Ensure result vectors are wider than the argument vector.
5536   auto *InputVT = cast<FixedVectorType>(Op->getType());
5537   auto *ResultVT = cast<FixedVectorType>(Shuf->getType());
5538   auto const InputNumElements = InputVT->getNumElements();
5539 
5540   if (InputNumElements >= ResultVT->getNumElements())
5541     return false;
5542 
5543   // Take the difference of the two shuffle masks at each index. Ignore poison
5544   // values at the same index in both masks.
5545   SmallVector<int, 16> NewMask;
5546   NewMask.reserve(Mask0.size());
