5561     return false;
5562 
5563   // Create new mask using difference of the two incoming masks.
5564   int MaskOffset = NewMask[0u];
5565   unsigned Index = (InputNumElements + MaskOffset) % InputNumElements;
5566   NewMask.clear();
5567 
5568   for (unsigned I = 0u; I < InputNumElements; ++I) {
5569     NewMask.push_back(Index);
5570     Index = (Index + 1u) % InputNumElements;
5571   }
